type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteInput = {
  customer: { yearsWithMHPCO: number };
  items: Item[];
  previousContracts: number;
};

export const quote = (input: QuoteInput): { premium: number } => {
  if (input.items.length === 0) {
    return { premium: 5 };
  }
  let total = 0;
  for (const item of input.items) {
    let base = 0;
    if (item.type === "sword") base = 100;
    // First-insurance surcharge: 10% per item for newcomers
    if (input.customer.yearsWithMHPCO === 0) {
      base += base * 0.1;
    }
    total += base;
  }
  total += 5; // processing fee
  return { premium: total };
};

export const claim = (_input: unknown): unknown => {
  return undefined;
};
